hd_form_scripts_hd_ticket.script:
/**
 * HD Form Script — 2 nút đồng cấp: ✨ AI Tóm tắt | ✨ AI Gợi ý trả lời
 * API: generate-ai-summary, generate-ai-reply, send-ai-reply
 */
async function setupForm({ doc, updateField, call, router, $dialog, createToast }) {
  const actions = [];
  // #region agent log
  setTimeout(async () => {
    try {
      const hasGitLabV3 = Array.from(document.querySelectorAll('button, a, [role=\"button\"]')).some((el) => String(el.textContent || '').includes('GitLab DBG V3'));
      await call('haravan_helpdesk.api.gitlab_popup_v2', { action: 'debug_ping', ticket_name: doc.name || '', note: hasGitLabV3 ? 'dom_has_gitlab_v3_yes' : 'dom_has_gitlab_v3_no' });
    } catch (e) {}
  }, 1200);
  // #endregion

  if (["Resolved", "Closed", "Rejected"].includes(doc.status)) {
    return { actions };
  }

  const toast = (opts) => {
    const o = Object.assign({}, opts);
    if (o.variant && !o.appearance) o.appearance = o.variant;
    createToast(o);
  };

  const normalizeResult = function (raw) {
    if (!raw) return {};
    if (raw.message && typeof raw.message === "object") return raw.message;
    return raw;
  };

  const esc = function (s) {
    if (window.frappe && frappe.utils && frappe.utils.escape_html) {
      return frappe.utils.escape_html(String(s ?? ""));
    }
    return String(s ?? "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  };

  const STYLE = `
        <style>
            .ai-reply-option-btn {
                padding: 0.25rem 1rem;
                border-radius: 0.75rem;
                cursor: pointer;
                margin-right: 0.5rem;
                background-color: #eee;
                border: none;
                font-size: 14px;
            }
            .ai-reply-option-btn.active {
                color: white;
                background-color: #171717;
            }
            .ai-summary-body { font-size: 14px; line-height: 1.6; color: #1c2126; }
            .ai-summary-body ul { margin: 8px 0 0 18px; }
        </style>
    `;

  window.__aiReplyOptions = [];

  window.selectReplyOption = function (index) {
    try {
      const opts = window.__aiReplyOptions || [];
      const opt = opts[index];
      if (!opt) return;
      const textarea = document.getElementById("ai-reply-content");
      if (textarea) textarea.value = opt.content || "";
      document.querySelectorAll(".ai-reply-option-btn").forEach(function (btn, i) {
        btn.classList.toggle("active", i === index);
      });
    } catch (e) {
      /* no-op */
    }
  };

  const buildReplyDialogHtml = function (options) {
    const optionBtns =
      options.length > 1
        ? "<div class=\"mb-4\">" +
          options
            .map(function (opt, i) {
              const label = esc((opt && opt.label) || "Gợi ý " + (i + 1));
              return (
                "<button class=\"ai-reply-option-btn" +
                (i === 0 ? " active" : "") +
                "\" onclick=\"selectReplyOption(" +
                i +
                ")\">" +
                label +
                "</button>"
              );
            })
            .join("") +
          "</div>"
        : "";

    const hint =
      options.length > 1
        ? "Chọn gợi ý phù hợp rồi chỉnh sửa nếu cần. Nội dung sẽ được gửi đến khách hàng."
        : "Nội dung sẽ được gửi reply đến khách hàng.";

    return (
      STYLE +
      "<div class=\"space-y-4 p-6\">" +
      optionBtns +
      "<div>" +
      "<label class=\"block text-sm font-medium text-gray-700 mb-2\">" +
      "Nội dung <span class=\"text-xs text-gray-500\">(có thể chỉnh sửa)</span>" +
      "</label>" +
      "<textarea id=\"ai-reply-content\" rows=\"12\" " +
      "class=\"w-full px-4 py-3 border border-gray-300 rounded-lg " +
      "focus:ring-2 focus:ring-blue-500 focus:border-blue-500 " +
      "outline-none resize-none text-sm leading-relaxed\">" +
      "</textarea>" +
      "<p class=\"text-xs text-gray-500 mt-2 italic\">" +
      hint +
      "</p>" +
      "</div>" +
      "</div>"
    );
  };

  const buildSummaryHtml = function (data) {
    const summary = esc((data && data.summary) || "");
    const bullets = (data && data.bullets) || [];
    const risks = (data && data.risks) || [];
    const next = (data && data.next_steps) || [];
    const conf =
      data && typeof data.confidence === "number"
        ? data.confidence
        : parseFloat((data && data.confidence) || 0);

    let bli = "";
    if (Array.isArray(bullets) && bullets.length) {
      bli = "<ul>" + bullets.map((b) => "<li>" + esc(b) + "</li>").join("") + "</ul>";
    }
    let rli = "";
    if (Array.isArray(risks) && risks.length) {
      rli =
        "<p class=\"text-sm font-medium mt-4\">Rủi ro / thiếu thông tin</p><ul>" +
        risks.map((b) => "<li>" + esc(b) + "</li>").join("") +
        "</ul>";
    }
    let nli = "";
    if (Array.isArray(next) && next.length) {
      nli =
        "<p class=\"text-sm font-medium mt-4\">Đề xuất bước tiếp theo</p><ul>" +
        next.map((b) => "<li>" + esc(b) + "</li>").join("") +
        "</ul>";
    }

    return (
      STYLE +
      "<div class=\"p-6 ai-summary-body\">" +
      "<p class=\"text-sm text-gray-500 mb-2\">Độ tin cậy AI: " +
      esc(String(isNaN(conf) ? 0 : conf)) +
      "</p>" +
      "<p class=\"font-medium mb-2\">Tóm tắt</p>" +
      "<p>" +
      summary +
      "</p>" +
      (bli ? "<p class=\"font-medium mt-4\">Điểm chính</p>" + bli : "") +
      rli +
      nli +
      "</div>"
    );
  };

  const openManualReplyDialog = function (prefill, reason) {
    $dialog({
      title: "✨ AI Gợi ý trả lời",
      html: buildReplyDialogHtml([{ label: "Soạn thủ công", content: prefill || "" }]),
      actions: [
        {
          label: "✉ Gửi reply",
          theme: "blue",
          variant: "solid",
          onClick(close) {
            const textarea = document.getElementById("ai-reply-content");
            const replyContent = textarea ? textarea.value.trim() : "";
            if (!replyContent) {
              toast({ title: "Lỗi", message: "Nội dung không được để trống", variant: "error" });
              return;
            }
            call("send-ai-reply", { ticket_id: doc.name, content: replyContent })
              .then(function (responseRaw) {
                const response = normalizeResult(responseRaw);
                if (response && response.success) {
                  close();
                  toast({ title: "Đã gửi", message: "Reply đã được gửi đến khách hàng!", variant: "success" });
                  setTimeout(function () {
                    window.location.reload();
                  }, 500);
                } else {
                  toast({
                    title: "Lỗi",
                    message: (response && response.error) || "Có lỗi khi gửi reply",
                    variant: "error",
                  });
                }
              })
              .catch(function (err) {
                toast({ title: "Lỗi", message: (err && err.message) || "Có lỗi khi gửi reply", variant: "error" });
              });
          },
        },
        { label: "Bỏ qua", theme: "gray", onClick(close) { close(); } },
      ],
    });
    setTimeout(function () {
      window.selectReplyOption(0);
    }, 50);
    if (reason) {
      toast({ title: "AI chưa sẵn sàng", message: reason, variant: "error" });
    }
  };

  actions.push({
    group: "AI",
    hideLabel: true,
    items: [
      {
        label: "✨ AI Tóm tắt",
        onClick: async () => {
          toast({ title: "Đang tóm tắt...", message: "AI đang phân tích nội dung ticket" });
          let result = {};
          try {
            const raw = await call("generate-ai-summary", { ticket_id: doc.name });
            result = normalizeResult(raw);
          } catch (err) {
            result = { success: false, error: (err && err.message) || "Không thể kết nối AI" };
          }
          if (!result.success) {
            toast({
              title: "Lỗi tóm tắt",
              message: (result && result.error) || "Không tạo được tóm tắt",
              variant: "error",
            });
            return;
          }
          try {
            $dialog({
              title: "✨ AI Tóm tắt",
              html: buildSummaryHtml(result),
              actions: [{ label: "Đóng", theme: "gray", onClick(close) { close(); } }],
            });
          } catch (dialogErr) {
            toast({
              title: "Lỗi hiển thị",
              message: (dialogErr && dialogErr.message) || "Không mở được popup",
              variant: "error",
            });
          }
        },
      },
      {
        label: "✨ AI Gợi ý trả lời",
        onClick: async () => {
          toast({ title: "Đang tạo gợi ý...", message: "AI đang phân tích nội dung ticket" });

          let result = {};
          try {
            const raw = await call("generate-ai-reply", { ticket_id: doc.name });
            result = normalizeResult(raw);
          } catch (err) {
            openManualReplyDialog("", (err && err.message) || "Không thể kết nối AI");
            return;
          }

          if (!result.success) {
            openManualReplyDialog("", (result && result.error) || "Không thể tạo gợi ý");
            return;
          }

          const options = result.options || [];
          if (!options.length) {
            openManualReplyDialog("", "AI không trả về gợi ý");
            return;
          }

          window.__aiReplyOptions = options;

          try {
            $dialog({
              title: "✨ AI Gợi ý trả lời",
              html: buildReplyDialogHtml(options),
              actions: [
                {
                  label: "✉ Gửi reply",
                  theme: "blue",
                  variant: "solid",
                  onClick(close) {
                    const textarea = document.getElementById("ai-reply-content");
                    const replyContent = textarea ? textarea.value.trim() : "";
                    if (!replyContent) {
                      toast({ title: "Lỗi", message: "Nội dung không được để trống", variant: "error" });
                      return;
                    }
                    call("send-ai-reply", { ticket_id: doc.name, content: replyContent })
                      .then(function (responseRaw) {
                        const response = normalizeResult(responseRaw);
                        if (response && response.success) {
                          close();
                          toast({
                            title: "Đã gửi",
                            message: "Reply đã được gửi đến khách hàng!",
                            variant: "success",
                          });
                          setTimeout(function () {
                            window.location.reload();
                          }, 500);
                        } else {
                          const detail =
                            response && response.debug_id ? " (ref: " + response.debug_id + ")" : "";
                          toast({
                            title: "Lỗi",
                            message: ((response && response.error) || "Có lỗi khi gửi reply") + detail,
                            variant: "error",
                          });
                        }
                      })
                      .catch(function (err) {
                        toast({
                          title: "Lỗi",
                          message: (err && err.message) || "Có lỗi khi gửi reply",
                          variant: "error",
                        });
                      });
                  },
                },
                { label: "Bỏ qua", theme: "gray", onClick(close) { close(); } },
              ],
            });
            setTimeout(function () {
              window.selectReplyOption(0);
            }, 50);
          } catch (dialogErr) {
            toast({
              title: "Lỗi hiển thị",
              message: (dialogErr && dialogErr.message) || "Không mở được popup gợi ý",
              variant: "error",
            });
          }
        },
      },
    ],
  });

  return { actions };
}

/**
 * HD Form Script - Customer Profile via Bitrix REST on-demand
 * Doctype: HD Ticket
 * Backend: haravan_bitrix_customer_profile
 */

async function setupForm({ doc, call, createToast }) {
  const METHOD = 'haravan_bitrix_customer_profile';
  const ROOT_ID = 'hv-bitrix-customer-profile';

  const esc = (value) => String(value == null ? '' : value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

  const getPayload = (res) => (res && res.message ? res.message : res);
  const toast = (title, message, variant = 'info') => {
    if (createToast) createToast({ title, message, variant });
  };

  const maskEmail = (email) => {
    const value = String(email || '');
    if (!value.includes('@')) return value;
    const parts = value.split('@');
    return `${parts[0].slice(0, 2)}***@${parts[1]}`;
  };

  const text = (value, empty = '-') => {
    const valueText = value == null ? '' : String(value).trim();
    return valueText ? esc(valueText) : `<span class="cp-muted">${empty}</span>`;
  };

  const link = (url, label) => {
    if (!url) return '<span class="cp-muted">-</span>';
    return `<a class="cp-link" href="${esc(url)}" target="_blank" rel="noopener noreferrer">${esc(label || url)}</a>`;
  };

  const field = (label, value) => `
    <div class="cp-field"><div class="cp-label">${esc(label)}</div><div class="cp-value">${value}</div></div>`;

  const preview = (obj) => {
    if (!obj) return '<div class="cp-empty">Chua co du lieu Bitrix.</div>';
    const keys = ['ID', 'TITLE', 'CONTACT_ID', 'COMPANY_ID', 'OPPORTUNITY', 'CURRENCY_ID', 'ASSIGNED_BY_ID', 'DATE_MODIFY', 'STAGE_ID', 'NAME', 'LAST_NAME', 'EMAIL', 'PHONE', 'COMPANY_TYPE', 'INDUSTRY'];
    const rows = keys
      .filter((key) => obj[key] != null && String(obj[key]) !== '')
      .map((key) => field(key, text(Array.isArray(obj[key]) || typeof obj[key] === 'object' ? JSON.stringify(obj[key]) : obj[key])))
      .join('');
    return rows || '<div class="cp-empty">Bitrix tra ve ban ghi nhung khong co truong hien thi.</div>';
  };

  const statusBadge = (payload) => {
    const bitrix = (payload.data && payload.data.bitrix) || {};
    const status = bitrix.status || 'unknown';
    const good = ['matched', 'contact_matched', 'cached'].includes(status);
    const warn = ['missing_config', 'disabled', 'not_found'].includes(status);
    const tone = good ? 'good' : warn ? 'warn' : 'neutral';
    return `<span class="cp-badge cp-badge--${tone}">${esc(status)}</span>`;
  };

  const render = (payload) => {
    const data = payload.data || {};
    const ticket = data.ticket || {};
    const customer = data.customer || {};
    const contact = data.contact || {};
    const bitrix = data.bitrix || {};
    const emails = data.emails || [];
    const phones = data.phones || [];
    const primaryEmail = contact.email_id || ticket.raised_by || (emails[0] && emails[0].email_id);
    const primaryPhone = contact.mobile_no || contact.phone || (phones[0] && phones[0].phone);

    return `
      <div class="cp-head">
        <div>
          <div class="cp-title">${text(customer.customer_name || customer.name || ticket.customer || 'Customer')}</div>
          <div class="cp-sub">Ticket ${text(ticket.name)} · ${text(customer.domain)} · Bitrix REST</div>
        </div>
        ${statusBadge(payload)}
      </div>

      <div class="cp-actions">
        <button type="button" class="cp-btn" data-cp-refresh>Refresh</button>
        <button type="button" class="cp-icon" title="Close" data-cp-close>x</button>
      </div>

      <section class="cp-section">
        <h3>Frappe + Haravan Identity</h3>
        ${field('HD Customer', text(customer.name || ticket.customer))}
        ${field('Domain', text(customer.domain))}
        ${field('Haravan OrgID', text(customer.custom_haravan_orgid))}
        ${field('MyHaravan', text(customer.custom_myharavan))}
        ${field('Contact', text(contact.full_name || contact.name || ticket.contact))}
        ${field('Email', text(maskEmail(primaryEmail)))}
        ${field('Phone', text(primaryPhone))}
      </section>

      <section class="cp-section">
        <h3>Bitrix Deal</h3>
        ${field('Deal ID', text(customer.custom_bitrix_deal_id || (bitrix.deal && bitrix.deal.ID)))}
        ${field('Link', link(customer.custom_bitrix_deal_url, 'Open deal'))}
        ${field('Owner', text(customer.custom_bitrix_deal_owner))}
        ${field('Service', text(customer.custom_bitrix_deal_service))}
        <div class="cp-json">${preview(bitrix.deal)}</div>
      </section>

      <section class="cp-section">
        <h3>Bitrix Company</h3>
        ${field('Company ID', text(customer.custom_bitrix_company_id || (bitrix.company && bitrix.company.ID)))}
        ${field('Link', link(customer.custom_bitrix_company_url, 'Open company'))}
        ${field('Confidence', text(customer.custom_bitrix_match_confidence ? `${customer.custom_bitrix_match_confidence}%` : ''))}
        ${field('Last Synced', text(customer.custom_bitrix_last_synced_at))}
        <div class="cp-json">${preview(bitrix.company)}</div>
      </section>

      <section class="cp-section">
        <h3>Bitrix Contact</h3>
        ${field('Contact ID', text(contact.custom_bitrix_contact_id || (bitrix.contact && bitrix.contact.ID)))}
        ${field('Link', link(contact.custom_bitrix_contact_url, 'Open contact'))}
        ${field('Last Synced', text(contact.custom_bitrix_last_synced_at))}
        <div class="cp-json">${preview(bitrix.contact)}</div>
      </section>

      ${bitrix.status === 'missing_config' ? '<div class="cp-note">Bitrix chua duoc cau hinh trong site config. Them custom key JSON ten bitrix voi Bitrix REST webhook/OAuth.</div>' : ''}
      ${payload.message ? `<div class="cp-note">${esc(payload.message)}</div>` : ''}
    `;
  };

  const ensurePanel = () => {
    let root = document.getElementById(ROOT_ID);
    if (root) return root;
    root = document.createElement('aside');
    root.id = ROOT_ID;
    root.innerHTML = `
      <style>
        #${ROOT_ID} { position: fixed; top: 0; right: 0; width: min(480px, 96vw); height: 100vh; background: #fff; color: #111827; border-left: 1px solid #d1d5db; box-shadow: -18px 0 48px rgba(15,23,42,.18); z-index: 9999; transform: translateX(105%); transition: transform .18s ease; font-size: 13px; }
        #${ROOT_ID}.open { transform: translateX(0); }
        #${ROOT_ID} * { box-sizing: border-box; }
        #${ROOT_ID} .cp-scroll { height: 100%; overflow: auto; padding: 16px; }
        #${ROOT_ID} .cp-head { display: flex; justify-content: space-between; gap: 12px; align-items: flex-start; padding: 4px 0 12px; border-bottom: 1px solid #e5e7eb; }
        #${ROOT_ID} .cp-title { font-size: 18px; font-weight: 700; line-height: 1.25; }
        #${ROOT_ID} .cp-sub, #${ROOT_ID} .cp-muted { color: #6b7280; font-size: 12px; }
        #${ROOT_ID} .cp-actions { display: flex; justify-content: flex-end; align-items: center; gap: 8px; margin: 12px 0; }
        #${ROOT_ID} .cp-btn, #${ROOT_ID} .cp-icon { border: 1px solid #d1d5db; background: #fff; color: #111827; border-radius: 6px; height: 32px; cursor: pointer; }
        #${ROOT_ID} .cp-btn { padding: 0 12px; font-weight: 600; }
        #${ROOT_ID} .cp-icon { width: 32px; font-size: 18px; line-height: 1; }
        #${ROOT_ID} .cp-section { border-top: 1px solid #e5e7eb; padding: 14px 0; }
        #${ROOT_ID} .cp-section h3 { margin: 0 0 10px; font-size: 12px; line-height: 1.2; text-transform: uppercase; letter-spacing: .06em; color: #4b5563; }
        #${ROOT_ID} .cp-field { display: grid; grid-template-columns: 132px 1fr; gap: 10px; padding: 6px 0; border-bottom: 1px solid #f3f4f6; }
        #${ROOT_ID} .cp-label { color: #6b7280; font-weight: 600; }
        #${ROOT_ID} .cp-value { min-width: 0; overflow-wrap: anywhere; }
        #${ROOT_ID} .cp-link { color: #2563eb; text-decoration: none; font-weight: 600; }
        #${ROOT_ID} .cp-badge { flex: 0 0 auto; border-radius: 999px; padding: 4px 9px; font-size: 11px; font-weight: 700; text-transform: uppercase; }
        #${ROOT_ID} .cp-badge--good { background: #dcfce7; color: #166534; }
        #${ROOT_ID} .cp-badge--warn { background: #fef3c7; color: #92400e; }
        #${ROOT_ID} .cp-badge--neutral { background: #e5e7eb; color: #374151; }
        #${ROOT_ID} .cp-json { margin-top: 8px; }
        #${ROOT_ID} .cp-empty, #${ROOT_ID} .cp-note { color: #6b7280; background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 6px; padding: 10px; line-height: 1.45; }
        #${ROOT_ID} .cp-loading { height: 100%; display: grid; place-items: center; color: #6b7280; }
        @media (max-width: 520px) { #${ROOT_ID} .cp-field { grid-template-columns: 1fr; gap: 2px; } }
      </style>
      <div class="cp-scroll"><div class="cp-loading">Loading customer profile...</div></div>`;
    document.body.appendChild(root);
    root.addEventListener('click', (event) => {
      if (event.target.closest('[data-cp-close]')) root.classList.remove('open');
      if (event.target.closest('[data-cp-refresh]')) load(true);
    });
    return root;
  };

  const load = async (refresh = false) => {
    const root = ensurePanel();
    root.classList.add('open');
    const scroll = root.querySelector('.cp-scroll');
    scroll.innerHTML = '<div class="cp-loading">Loading customer profile...</div>';
    try {
      const res = await call(METHOD, { ticket: doc.name, refresh: refresh ? 1 : 0 });
      const payload = getPayload(res) || {};
      if (!payload.success) {
        scroll.innerHTML = `<div class="cp-actions"><button type="button" class="cp-icon" title="Close" data-cp-close>x</button></div><div class="cp-empty">${esc(payload.message || 'Unable to load customer profile')}</div>`;
        toast('Customer Profile', payload.message || 'Unable to load customer profile', 'error');
        return;
      }
      scroll.innerHTML = render(payload);
    } catch (error) {
      const message = error && error.message ? error.message : 'Unable to load customer profile';
      scroll.innerHTML = `<div class="cp-actions"><button type="button" class="cp-icon" title="Close" data-cp-close>x</button></div><div class="cp-empty">${esc(message)}</div>`;
      toast('Customer Profile', message, 'error');
    }
  };

  return {
    actions: [
      { group: 'Customer', hideLabel: true, items: [{ label: 'Customer Profile', variant: 'solid', theme: 'gray', onClick: () => load(false) }] },
    ],
  };
}

// This script is auto-generated by the Field Dependency feature. 
// It is not meant to be modified directly. 

function setupForm({doc, updateField, call, router, toast, $dialog, createToast ,applyFilters}) {

    function update_custom_service_line(value){
        if(value=="User guide") {
            options = ["Thu thập thông tin","Thiết kế","Sản xuất nội dung","HTML coding","Triển khai","Nghiệm thu","Bảo hành","Báo giá","Outsourcing"]
            applyFilters("custom_service_line",options)
        }

        else {
            applyFilters("custom_service_line",[])
        }
    }


   return {
        onChange: {
            custom_internal_type: (newVal) => update_custom_service_line(newVal)
        }
    }

