function setupForm({ doc, call, createToast }) {
  const state = window.__haravanAiAnalyzeState || (window.__haravanAiAnalyzeState = {});

  async function runAiAnalysis() {
    if (!doc.name) {
      createToast?.({
        title: "Chưa thể phân tích",
        message: "Ticket cần được tạo trước khi chạy AI phân tích.",
        variant: "error",
      });
      return;
    }

    if (!doc.subject && !doc.description) {
      createToast?.({
        title: "Thiếu dữ liệu",
        message: "Cần có tiêu đề hoặc mô tả ticket để AI phân tích.",
        variant: "error",
      });
      return;
    }

    if (state[doc.name]) {
      createToast?.({
        title: "Đang xử lý",
        message: "AI đang phân tích ticket này, vui lòng chờ thêm một chút.",
        variant: "info",
      });
      return;
    }

    state[doc.name] = true;

    createToast?.({
      title: "AI đang phân tích",
      message: "Đang làm giàu dữ liệu ticket...",
      variant: "info",
    });

    try {
      const response = await call("haravan_ai_analyze_ticket", {
        name: doc.name,
      });

      const payload = response && response.data ? response.data : response;
      const updatedFields = (payload && payload.updated_fields) || [];
      const recognizedFields = payload && payload.recognized_fields ? Object.keys(payload.recognized_fields) : [];
      const reasoning = (payload && payload.reasoning) || "";
      const internalCommentCreated = !!(payload && payload.internal_comment_created);

      createToast?.({
        title: "AI phân tích hoàn tất",
        message:
          updatedFields.length > 0
            ? `Đã làm giàu ${updatedFields.length} trường.${internalCommentCreated ? " Đã ghi internal comment." : ""}${reasoning ? ` ${reasoning}` : ""}`
            : recognizedFields.length > 0
              ? `AI đã nhận diện ${recognizedFields.length} trường, nhưng ticket hiện đã có dữ liệu hoặc không cần ghi đè.${internalCommentCreated ? " Đã ghi internal comment." : ""}`
              : `AI chưa đủ tín hiệu để làm giàu thêm.${internalCommentCreated ? " Đã ghi internal comment." : ""}`,
        variant: "success",
      });

      setTimeout(() => window.location.reload(), 600);
    } catch (error) {
      const message =
        (error && error.message) ||
        "AI chưa thể phân tích ticket lúc này. Vui lòng thử lại sau.";

      createToast?.({
        title: "AI phân tích thất bại",
        message,
        variant: "error",
      });
    } finally {
      delete state[doc.name];
    }
  }

  return {
    actions: [
      {
        label: "✨ AI Phân tích",
        onClick: runAiAnalysis,
        variant: "solid",
        theme: "blue",
      },
    ],
  };
}

// HD Form Script - GitLab Popup V5
// Doctype: HD Ticket
//
// Redesigned UI to match Frappe Helpdesk design language:
//   - CSS-class based styling (no massive inline styles)
//   - Clean tabs, refined cards, better button hierarchy
//   - Smart search with debounce (no explicit "Tìm" button)
//   - Preload open issues when switching to search tab
//   - Auto-switch to "Liên kết hiện tại" if already linked
//   - Loading spinner, proper empty states
//
// Backend: haravan_helpdesk.api.gitlab_popup_v2

async function setupForm({
    doc,
    updateField,
    call,
    router,
    $dialog,
    createToast
}) {
    const actions = [];
    const API_METHOD = 'haravan_helpdesk.api.gitlab_popup_v2';

    const esc = (v) => String(v ?? '')
        .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;').replace(/'/g, '&#39;');

    const plainText = (html) => {
        const d = document.createElement('div');
        d.innerHTML = String(html || '');
        return (d.textContent || d.innerText || '').trim();
    };

    const api = async (action, args = {}) => {
        const r = await call(API_METHOD, { action, ...args });
        return r?.message || r || {};
    };

    const getErr = (e, fallback = 'Có lỗi xảy ra') =>
        e?.messages?.[0] || e?.message || e?.exc_type || fallback;

    const toast = (title, message, variant = 'info') =>
        createToast?.({ title, message, variant });

    const openDialog = async () => {
        if (!doc.name) {
            toast('Chưa lưu ticket', 'Vui lòng lưu ticket trước khi thao tác GitLab.', 'warning');
