        const id = `glp-${Date.now()}`;
        const sk = `__hdgl_${id}`;
        const ticket = init.ticket || {};
        const defTitle = ticket.subject || doc.subject || `Ticket #${doc.name}`;
        const defDesc = plainText(ticket.description || doc.description || doc.content || '');

        const css = `
