            }
            #${id} .gl-results { max-height: 300px; overflow-y: auto; }
            #${id} .gl-section-label {
                font-size: 11px; font-weight: 600; letter-spacing: 0.05em;
                text-transform: uppercase; color: #9ca3af; margin: 14px 0 6px;
            }
            #${id} .gl-comments { max-height: 180px; overflow-y: auto; }
            #${id} .gl-cmt { padding: 8px 0; border-bottom: 1px solid #f3f4f6; }
            #${id} .gl-cmt:last-child { border-bottom: none; }
            #${id} .gl-cmt-author { font-size: 12px; font-weight: 600; color: #374151; }
            #${id} .gl-cmt-body { font-size: 13px; color: #4b5563; white-space: pre-wrap; margin-top: 2px; }
            #${id} .gl-spinner {
                display: inline-block; width: 13px; height: 13px;
                border: 2px solid #e5e7eb; border-top-color: #6b7280;
                border-radius: 50%; animation: glSpin 0.6s linear infinite; vertical-align: middle;
            }
            @keyframes glSpin { to { transform: rotate(360deg); } }
            :is(.modal, .frappe-dialog, .frappe-ui-dialog):has(#${id}) .frappe-ui-dialog__footer,
            :is(.modal, .frappe-dialog, .frappe-ui-dialog):has(#${id}) .dialog-footer,
            :is(.modal, .frappe-dialog, .frappe-ui-dialog):has(#${id}) footer {
                display: none !important;
            }
            @media (max-width: 768px) {
