                #${id} .gl-card-actions { justify-content: flex-start; margin-top: 8px; }
            }
        `;

        window[sk] = {
            _timer: null,

            badge(state) {
                const v = String(state || 'unknown').toLowerCase();
                const cls = v === 'opened' ? 'gl-badge-open' : 'gl-badge-closed';
                return `<span class="gl-badge ${cls}">${esc(state || 'unknown')}</span>`;
            },

            issueCard(issue, actionsHtml = '') {
                const iid = String(issue?.iid || issue?.issue_iid || '');
                const url = issue?.web_url || '';
                const link = url
                    ? `<a class="gl-link" href="${esc(url)}" target="_blank" rel="noopener noreferrer">Mở GitLab ↗</a>`
                    : '';
                const updatedAt = issue?.updated_at;
                const date = updatedAt ? new Date(updatedAt).toLocaleDateString('vi-VN') : '';
                return `<div class="gl-card">
                    <div class="gl-card-main">
                        <div class="gl-card-content">
                            <div class="gl-card-title">!${esc(iid)} &mdash; ${esc(issue?.title || 'Không có tiêu đề')}</div>
                            <div class="gl-card-meta">
                                ${this.badge(issue?.state)}
                                ${date ? `<span>${esc(date)}</span>` : ''}
                                ${link}
                            </div>
                        </div>
                        ${actionsHtml ? `<div class="gl-card-actions">${actionsHtml}</div>` : ''}
                    </div>
                </div>`;
            },

            switchTab(tab) {
                this.activeTab = tab;
                document.querySelectorAll(`#${id} .gl-tab-btn`).forEach(b => {
                    b.classList.toggle('active', b.dataset.glTab === tab);
                });
                document.querySelectorAll(`#${id} [data-gl-pane]`).forEach(p => {
                    p.style.display = p.dataset.glPane === tab ? 'block' : 'none';
                });
                if (tab === 'current') this.loadCurrent();
                if (tab === 'search') this.preloadSearch();
            },

            preloadSearch() {
                const q = (document.getElementById(`${id}-query`)?.value || '').trim();
                this.doSearch(q);
            },

            onQueryInput(e) {
                clearTimeout(this._timer);
                const q = (e.target.value || '').trim();
                this._timer = setTimeout(() => this.doSearch(q), 350);
            },

            async doSearch(query = '') {
                const el = document.getElementById(`${id}-results`);
                if (!el) return;
                el.innerHTML = '<div class="gl-loading"><span class="gl-spinner"></span></div>';
                try {
                    const r = await api('search', { query: query.replace(/^[#!]/, ''), limit: 30 });
                    const issues = r.issues || [];
                    if (!issues.length) {
                        el.innerHTML = `<div class="gl-empty">${query ? 'Không tìm thấy issue phù hợp.' : 'Chưa có issue nào đang mở.'}</div>`;
                        return;
                    }
                    el.innerHTML = issues.map(issue => this.issueCard(
                        issue,
                        `<button class="gl-btn gl-btn-sm" type="button"
                            onclick="window['${sk}'].linkIssue('${esc(String(issue.iid))}')">Liên kết</button>`
                    )).join('');
                } catch (e) {
                    el.innerHTML = `<div class="gl-empty" style="color:#dc2626;">Không thể tải issue từ GitLab.</div>`;
                }
            },

            async linkIssue(iid) {
                const el = document.getElementById(`${id}-results`);
                if (el) el.innerHTML = '<div class="gl-loading"><span class="gl-spinner"></span> Đang liên kết...</div>';
                try {
                    const r = await api('link', { ticket_name: doc.name, iid });
                    this.linkedIssue = r.issue || null;
                    toast('Đã liên kết', 'GitLab issue đã được liên kết với ticket.', 'success');
                    this.switchTab('current');
                } catch (e) {
                    if (el) el.innerHTML = `<div class="gl-msg-error">${esc(getErr(e))}</div>`;
                }
            },

            async createIssue() {
                const titleEl = document.getElementById(`${id}-title`);
                const title = (titleEl?.value || '').trim();
                if (!title) { titleEl?.focus(); return; }

                const btn = document.getElementById(`${id}-create-btn`);
                const errEl = document.getElementById(`${id}-create-err`);
                if (errEl) errEl.innerHTML = '';
                if (btn) { btn.disabled = true; btn.textContent = 'Đang tạo...'; }

                try {
                    const r = await api('create', {
                        ticket_name: doc.name,
                        title,
                        description: document.getElementById(`${id}-description`)?.value || '',
                        labels: document.getElementById(`${id}-labels`)?.value || 'helpdesk,customer-report'
                    });
                    this.linkedIssue = r.issue || null;
                    toast('Đã tạo issue', 'GitLab issue đã được tạo và liên kết.', 'success');
                    this.switchTab('current');
                } catch (e) {
                    if (errEl) errEl.innerHTML = `<div class="gl-msg-error">${esc(getErr(e))}</div>`;
                    if (btn) { btn.disabled = false; btn.textContent = 'Tạo & liên kết'; }
                }
            },

            async loadCurrent() {
                const el = document.getElementById(`${id}-current`);
                if (!el) return;
                el.innerHTML = '<div class="gl-loading"><span class="gl-spinner"></span> Đang tải...</div>';
                try {
                    const r = await api('detail', { ticket_name: doc.name, limit: 20 });
                    if (!r.linked || !r.issue) {
                        el.innerHTML = `<div class="gl-empty">
                            Ticket này chưa liên kết GitLab issue nào.<br>
                            <button class="gl-btn" type="button" style="margin-top:10px;"
                                onclick="window['${sk}'].switchTab('search')">Tìm & liên kết issue</button>
                        </div>`;
                        return;
                    }
                    this.linkedIssue = r.issue;
                    this.comments = r.comments || [];
                    const cmtsHtml = this.comments.length
                        ? this.comments.map(c => `<div class="gl-cmt">
                            <div class="gl-cmt-author">${esc(c.author || 'Unknown')}</div>
                            <div class="gl-cmt-body">${esc(c.body || '')}</div>
                          </div>`).join('')
                        : '<div style="color:#9ca3af;font-size:13px;padding:4px 0;">Chưa có comment nào.</div>';
                    el.innerHTML = `
                        ${this.issueCard(r.issue, `
                            <button class="gl-btn gl-btn-sm" type="button"
                                onclick="window['${sk}'].syncIssue()">Đồng bộ</button>
                            <button class="gl-btn gl-btn-danger gl-btn-sm" type="button"
                                onclick="window['${sk}'].unlinkIssue()">Gỡ liên kết</button>
                        `)}
                        <div class="gl-section-label">Comments GitLab (${this.comments.length})</div>
                        <div class="gl-card gl-comments">${cmtsHtml}</div>
                    `;
                } catch (e) {
                    el.innerHTML = `<div class="gl-msg-error">Không thể tải thông tin liên kết.</div>`;
                }
            },

            async syncIssue() {
                try {
                    await api('sync', { ticket_name: doc.name, limit: 20 });
                    toast('Đã đồng bộ', 'Thông tin GitLab đã được cập nhật.', 'success');
                    await this.loadCurrent();
                } catch (e) {
                    toast('Lỗi đồng bộ', getErr(e), 'error');
                }
            },

            async unlinkIssue() {
                if (!window.confirm('Gỡ liên kết GitLab issue khỏi ticket này?')) return;
                const el = document.getElementById(`${id}-current`);
                if (el) el.innerHTML = '<div class="gl-loading"><span class="gl-spinner"></span> Đang gỡ...</div>';
                try {
                    await api('unlink', { ticket_name: doc.name });
                    this.linkedIssue = null;
                    toast('Đã gỡ liên kết', 'Ticket không còn liên kết GitLab issue.', 'success');
                    await this.loadCurrent();
                } catch (e) {
                    toast('Lỗi gỡ liên kết', getErr(e), 'error');
                    await this.loadCurrent();
                }
            }
        };

        $dialog({
            title: 'GitLab',
            html: `
                <style>${css}</style>
                <div id="${id}">
                    <div class="gl-tabs">
                        <button class="gl-tab-btn active" type="button" data-gl-tab="create"
                            onclick="window['${sk}'].switchTab('create')">Tạo mới</button>
                        <button class="gl-tab-btn" type="button" data-gl-tab="search"
                            onclick="window['${sk}'].switchTab('search')">Tìm & liên kết</button>
                        <button class="gl-tab-btn" type="button" data-gl-tab="current"
                            onclick="window['${sk}'].switchTab('current')">Liên kết hiện tại</button>
                    </div>

                    <div data-gl-pane="create">
                        <div class="gl-field">
                            <label class="gl-label" for="${id}-title">Tiêu đề <span style="color:#ef4444">*</span></label>
                            <input id="${id}-title" class="gl-input" type="text"
                                value="${esc(defTitle)}" placeholder="Tiêu đề GitLab issue">
                        </div>
                        <div class="gl-field">
                            <label class="gl-label" for="${id}-description">Mô tả</label>
                            <textarea id="${id}-description" class="gl-textarea" rows="6"
                                placeholder="Mô tả chi tiết...">${esc(defDesc)}</textarea>
                        </div>
                        <div class="gl-field">
                            <label class="gl-label" for="${id}-labels">Labels</label>
                            <input id="${id}-labels" class="gl-input" type="text"
                                value="helpdesk,customer-report"
                                placeholder="Labels phân cách bởi dấu phẩy">
                        </div>
                        <button id="${id}-create-btn" class="gl-btn gl-btn-primary" type="button"
                            onclick="window['${sk}'].createIssue()">Tạo & liên kết</button>
                        <div id="${id}-create-err"></div>
                    </div>

                    <div data-gl-pane="search" style="display:none;">
                        <div class="gl-field">
                            <input id="${id}-query" class="gl-input" type="text"
                                placeholder="Tìm theo tiêu đề hoặc nhập IID (vd: 123)..."
                                oninput="window['${sk}'].onQueryInput(event)">
                        </div>
                        <div id="${id}-results" class="gl-results">
                            <div class="gl-empty">Chuyển sang tab này để xem các issue đang mở.</div>
                        </div>
                    </div>

                    <div data-gl-pane="current" style="display:none;">
                        <div id="${id}-current"></div>
                    </div>
                </div>`
        });

        if (init.issue) {
            window[sk].switchTab('current');
        }
    };

    actions.push({
        label: 'GitLab',
        variant: 'solid',
        theme: 'gray',
        onClick: openDialog
    });

    return { actions };
}

function setupForm({ doc, call, applyFilters, createToast }) {
  const state = window.__haravanRaisedByLookupState || (window.__haravanRaisedByLookupState = {
    requestId: 0,
    customers: [],
    lastEmail: ""
  });

  const FIELDS = [
    "raised_by",
    "contact",
    "custom_contact_phone",
    "customer",
    "custom_store_url",
    "custom_orgid",
    "custom_my_haravan_domain"
  ];

  function text(value) {
    return String(value || "").trim();
  }

  function isEmail(value) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(text(value));
  }

  function unique(values) {
    return [...new Set((values || []).map((value) => text(value)).filter(Boolean))];
  }

  function findFieldInput(fieldname) {
    const selectors = [
      `[name="${fieldname}"]`,
      `[data-fieldname="${fieldname}"] input`,
      `[data-fieldname="${fieldname}"] textarea`,
      `[data-fieldname="${fieldname}"] select`,
      `#${fieldname}`
    ];

    for (const selector of selectors) {
      const element = document.querySelector(selector);
      if (element) return element;
    }
    return null;
  }

  function dispatchInputEvents(input) {
    input.dispatchEvent(new Event("input", { bubbles: true }));
    input.dispatchEvent(new Event("change", { bubbles: true }));
    input.dispatchEvent(new Event("blur", { bubbles: true }));
  }

  function setFieldValue(fieldname, value, { overwrite = false } = {}) {
    const normalized = text(value);
    if (!normalized) return false;

    const current = text(doc[fieldname]);
    if (current && current !== normalized && !overwrite) return false;

    doc[fieldname] = normalized;
    const input = findFieldInput(fieldname);
    if (input && (overwrite || !text(input.value) || text(input.value) === current)) {
      input.value = normalized;
      dispatchInputEvents(input);
    }
    return true;
  }

  function ensureHint(fieldname, attrName) {
    const input = findFieldInput(fieldname);
    if (!input) return null;
    const parent = input.parentElement || input;
    let hint = parent.querySelector(`[data-${attrName}]`);
    if (hint) return hint;

    hint = document.createElement("div");
    hint.setAttribute(`data-${attrName}`, "1");
    hint.className = "mt-1 text-xs text-slate-500";
    parent.appendChild(hint);
    return hint;
  }

  function setHint(fieldname, attrName, message, tone = "default") {
    const hint = ensureHint(fieldname, attrName);
    if (!hint) return;
    hint.textContent = message || "";
    hint.className = "mt-1 text-xs";
    hint.classList.add(tone === "info" ? "text-sky-600" : tone === "warn" ? "text-amber-600" : "text-slate-500");
  }

  function customerLabel(customer) {
    const bits = [customer.customer_name || customer.name];
    if (customer.last_orgid || customer.custom_orgid) bits.push(`Org ID: ${customer.last_orgid || customer.custom_orgid}`);
    if (customer.last_myharavan_domain || customer.custom_my_haravan_domain) bits.push(customer.last_myharavan_domain || customer.custom_my_haravan_domain);
    return bits.filter(Boolean).join(" - ");
  }

  function fillFromCustomer(customer, { overwrite = false } = {}) {
    if (!customer) return;
    setFieldValue("customer", customer.name, { overwrite });
    setFieldValue("custom_store_url", customer.last_store_url || customer.domain, { overwrite });
    setFieldValue("custom_orgid", customer.last_orgid || customer.custom_orgid, { overwrite });
    setFieldValue("custom_my_haravan_domain", customer.last_myharavan_domain || customer.custom_my_haravan_domain, { overwrite });
  }

  function applyLookupResult(data, email) {
    const defaults = data.defaults || {};
    const customers = data.customers || [];
    const contacts = data.contacts || [];
    const phones = data.phones || [];

    state.customers = customers;
    state.lastEmail = email;

    if (defaults.contact) setFieldValue("contact", defaults.contact);
    if (defaults.custom_contact_phone) setFieldValue("custom_contact_phone", defaults.custom_contact_phone);

    const customerNames = unique(customers.map((customer) => customer.name));
    applyFilters("customer", customerNames.length ? customerNames : null);

    if (customers.length === 1) {
      fillFromCustomer(customers[0]);
      createToast?.({
        title: "Đã gợi ý dữ liệu khách hàng",
        message: `Tìm thấy Contact ${defaults.contact || contacts[0]?.name || ""} và Customer ${customers[0].name}. Hệ thống đã tự điền các trường liên quan.`,
        variant: "info"
      });
    } else if (customers.length > 1) {
      setHint(
        "customer",
        "haravan-raised-by-customer-hint",
        `Email này liên quan ${customers.length} Customer. Dropdown Customer đã được lọc, vui lòng chọn đúng org/customer.`,
        "warn"
      );
      createToast?.({
        title: "Cần chọn Customer",
        message: `Email ${email} có nhiều org/customer: ${customers.slice(0, 3).map(customerLabel).join("; ")}`,
        variant: "info"
      });
    } else {
      setHint("customer", "haravan-raised-by-customer-hint", "Chưa tìm thấy Customer từ email này. Có thể để trống hoặc chọn thủ công.");
      createToast?.({
        title: "Chưa có hồ sơ Customer",
        message: `Không tìm thấy Customer cho ${email}. Ticket vẫn có thể tạo với Raised By là email này.`,
        variant: "info"
      });
    }

    if (phones.length > 1) {
      setHint("custom_contact_phone", "haravan-raised-by-phone-hint", `Số điện thoại từng dùng: ${phones.slice(0, 3).join(" / ")}.`, "info");
    }
  }

  async function lookupRaisedBy(email, { showFeedback = true } = {}) {
    const cleanEmail = text(email);
    if (!isEmail(cleanEmail)) return;

    const requestId = state.requestId + 1;
    state.requestId = requestId;

    if (showFeedback) {
      setHint("raised_by", "haravan-raised-by-hint", "Đang tra cứu Contact / Customer / Org ID từ email...", "info");
    }

    const result = await call("haravan_raised_by_ticket_context", { email: cleanEmail }).catch((error) => {
      console.error("[Haravan] raised_by lookup failed", error);
      return null;
    });

    if (state.requestId !== requestId) return;

    if (!result || result.success === false) {
      setHint("raised_by", "haravan-raised-by-hint", result?.message || "Không tra cứu được dữ liệu từ email này.", "warn");
      return;
    }

    const data = result.data || result;
    setHint("raised_by", "haravan-raised-by-hint", `Đã tra cứu email ${cleanEmail}.`, "info");
    applyLookupResult(data, cleanEmail);
  }

  function bindRaisedByInput() {
    const input = findFieldInput("raised_by");
    if (!input || input.dataset.haravanRaisedByLookupBound === "1") return;
    input.dataset.haravanRaisedByLookupBound = "1";
    input.setAttribute("autocomplete", "email");

    let timer = null;
    const scheduleLookup = () => {
      window.clearTimeout(timer);
      timer = window.setTimeout(() => lookupRaisedBy(input.value, { showFeedback: true }), 500);
    };

    input.addEventListener("input", scheduleLookup);
    input.addEventListener("change", () => lookupRaisedBy(input.value, { showFeedback: true }));
    input.addEventListener("blur", () => lookupRaisedBy(input.value, { showFeedback: false }));
  }

  function bindCustomerInput() {
    const input = findFieldInput("customer");
    if (!input || input.dataset.haravanCustomerLookupBound === "1") return;
    input.dataset.haravanCustomerLookupBound = "1";
    input.addEventListener("change", () => {
      const selected = text(input.value || doc.customer);
      const match = state.customers.find((customer) => customer.name === selected);
      if (match) fillFromCustomer(match, { overwrite: true });
    });
  }

  function bindAll() {
    FIELDS.forEach((fieldname) => findFieldInput(fieldname));
    bindRaisedByInput();
    bindCustomerInput();
  }

  [0, 250, 800, 1500].forEach((delay) => window.setTimeout(bindAll, delay));

  if (isEmail(doc.raised_by)) {
    window.setTimeout(() => lookupRaisedBy(doc.raised_by, { showFeedback: false }), 300);
  }

  return {
    onChange: {
      raised_by: (newVal) => lookupRaisedBy(newVal || doc.raised_by, { showFeedback: true }),
      customer: (newVal) => {
        const selected = text(newVal || doc.customer);
        const match = state.customers.find((customer) => customer.name === selected);
        if (match) fillFromCustomer(match, { overwrite: true });
      }
    }
  };
}

