// Name: HD Ticket Agent Intake Autofill UX
// Goal: personalize the agent new-ticket page. Agents only enter Link Web / MyHaravan
//       and Product Suggestion; derived fields stay hidden and are filled by Server Scripts.
// Related fields: customer, custom_store_url, custom_orgid, custom_my_haravan_domain,
//                 custom_myharavan_domain, custom_product_suggestion,
//                 custom_product_line, custom_product_feature.
function setupForm({ doc, createToast }) {
  const hiddenLabels = ["Customer", "Org ID", "MyHaravan Domain", "Product Line", "Product Feature"];
  const hiddenFieldnames = [
    "customer",
    "custom_orgid",
    "custom_my_haravan_domain",
    "custom_myharavan_domain",
    "custom_product_line",
    "custom_product_feature"
  ];
  const requiredLabels = ["Link Web / MyHaravan", "Product Suggestion"];
  const requiredFieldnames = ["custom_store_url", "custom_product_suggestion"];

  function isNewTicketForm() {
    return !doc.name || window.location.pathname.includes("/helpdesk/tickets/new") || window.location.pathname.includes("/helpdesk/my-tickets/new");
  }

  function cleanText(value) {
    return String(value || "").replace(/\s+/g, " ").replace(/ \*/g, "").trim();
  }

  function findByFieldname(fieldname) {
    const target = document.querySelector(`[name="${fieldname}"], #${fieldname}, [data-fieldname="${fieldname}"]`);
    if (!target) return null;
    return target.closest("[data-fieldname], .form-group, .field, .frappe-control") || target.parentElement;
  }

  function fieldContainerFromLabel(labelText) {
    const nodes = document.querySelectorAll("label, div, span, p");
    for (const node of nodes) {
      if (cleanText(node.textContent) !== labelText) continue;

      let current = node;
      for (let depth = 0; current && depth < 8; depth += 1) {
        if (
          current !== document.body &&
          current.querySelector &&
          current.querySelector("input, textarea, select, button, [role='combobox']")
        ) {
          return current;
        }
        current = current.parentElement;
      }
    }
    return null;
  }

  function hideContainer(container) {
    if (!container) return;
    container.style.setProperty("display", "none", "important");
    container.setAttribute("data-haravan-agent-hidden", "1");
  }

  function hideDerivedFields() {
    if (!isNewTicketForm()) return;

    hiddenFieldnames.forEach((fieldname) => hideContainer(findByFieldname(fieldname)));
    hiddenLabels.forEach((label) => hideContainer(fieldContainerFromLabel(label)));
  }

  function markRequired() {
    if (!isNewTicketForm()) return;

    requiredFieldnames.forEach((fieldname) => {
      const container = findByFieldname(fieldname);
      const input = container?.querySelector("input, textarea, select, button, [role='combobox']");
      input?.setAttribute("aria-required", "true");
    });

    requiredLabels.forEach((labelText) => {
      const container = fieldContainerFromLabel(labelText) || findByFieldname(labelText === "Link Web / MyHaravan" ? "custom_store_url" : "custom_product_suggestion");
      const label = container?.querySelector("label, div, span, p");
      if (label && !label.querySelector("[data-haravan-required-star]")) {
        const star = document.createElement("span");
        star.setAttribute("data-haravan-required-star", "1");
        star.style.color = "#dc2626";
        star.textContent = " *";
        label.appendChild(star);
      }
    });
  }

  function refreshAgentTemplate() {
    hideDerivedFields();
    markRequired();
  }

  [0, 100, 300, 700, 1200, 2500, 5000].forEach((delay) => window.setTimeout(refreshAgentTemplate, delay));

  if (!window.__haravanAgentTicketTemplateObserver) {
    window.__haravanAgentTicketTemplateObserver = true;
    const observer = new MutationObserver(() => refreshAgentTemplate());
    observer.observe(document.body, { childList: true, subtree: true });
  }

  if (!window.__haravanAgentTicketSubmitGuard) {
    window.__haravanAgentTicketSubmitGuard = true;
    document.addEventListener("submit", (event) => {
      if (!isNewTicketForm()) return;

      const missing = requiredLabels.filter((labelText) => {
        const container = fieldContainerFromLabel(labelText) || findByFieldname(labelText === "Link Web / MyHaravan" ? "custom_store_url" : "custom_product_suggestion");
        const input = container?.querySelector("input, textarea, select");
        const combobox = container?.querySelector("button, [role='combobox']");
        const value = input ? input.value : cleanText(combobox?.textContent || "");
        return !value || value === "Select an option" || value === "Type something";
      });

      if (!missing.length) return;

      event.preventDefault();
      event.stopPropagation();
      createToast?.({
        title: "Thiếu thông tin bắt buộc",
        message: "Vui lòng nhập Link Web / MyHaravan và chọn Product Suggestion trước khi tạo ticket.",
        variant: "error"
      });
    }, true);
  }

  return {
    onChange: {
      custom_store_url: () => refreshAgentTemplate(),
      custom_product_suggestion: () => refreshAgentTemplate()
    }
  };
}

function setupForm({ doc, applyFilters, call, createToast }) {
  const productLineOptions = ["HaraWeb", "HaraSocial", "HaraRetail", "HaraCRM", "HaraInvoice", "HaraCampaign", "Khác"];
  const functionOptionsByProductLine = {
    HaraWeb: ["Giao diện / Theme", "Trang chủ / Landing page", "Menu / Header / Footer", "Blog / Nội dung", "SEO / Meta / Pixel", "App embed", "Hiệu năng / Page speed"],
    HaraSocial: ["Livestream", "Chat automation", "Comment / Inbox", "Kịch bản bán hàng", "Kết nối kênh social"],
    HaraRetail: ["POS / Bán tại quầy", "Sản phẩm / Tồn kho", "Đơn hàng", "Khuyến mãi", "Khách hàng / Loyalty"],
    HaraCRM: ["Contact / Lead", "Phân nhóm khách hàng", "Automation", "Form / Thu thập lead"],
    HaraInvoice: ["Hóa đơn điện tử", "Thông tin doanh nghiệp", "Mã số thuế", "Phát hành hóa đơn"],
    HaraCampaign: ["Email campaign", "SMS campaign", "Automation journey", "Template campaign"],
    "Khác": ["Khác"]
  };
  const htmlTicketTypes = ["Hỗ trợ giao diện Website", "Feature Customize (Cusedit)"];
  const phoneFieldname = "custom_contact_phone";
  const phoneState = window.__haravanTicketPhoneState || (window.__haravanTicketPhoneState = {
    suggestedPhones: [],
    submitBound: false,
    requestId: 0
  });
  const customerState = window.__haravanTicketCustomerState || (window.__haravanTicketCustomerState = {
    suggestedCustomers: [],
    requestId: 0
  });

  function productOptions(ticketType) {
    if (htmlTicketTypes.includes(ticketType)) {
      return ["HaraWeb", "Khác"];
    }

    return productLineOptions;
  }

  function functionOptions(productLine) {
    if (!productLine) {
      return Object.values(functionOptionsByProductLine).flat();
    }

    return functionOptionsByProductLine[productLine] || ["Khác"];
  }

  function unique(values) {
    return [...new Set((values || []).map((value) => String(value || "").trim()).filter(Boolean))];
  }

  function isNewTicketForm() {
    return !doc.name || window.location.pathname.includes("/helpdesk/tickets/new");
  }

  function hideCreateOnlyClassificationFields() {
    const styleId = "haravan-create-classification-hidden-fields";

    if (!isNewTicketForm()) {
      document.getElementById(styleId)?.remove();
      return;
    }

    let style = document.getElementById(styleId);
    if (!style) {
      style = document.createElement("style");
      style.id = styleId;
      style.textContent = `
        [data-fieldname="custom_product_suggestion_title"],
        [data-fieldname="custom_product_line"],
        [data-fieldname="custom_product_feature"] {
          display: none !important;
        }
      `;
      document.head.appendChild(style);
    }

    ["custom_product_suggestion_title", "custom_product_line", "custom_product_feature"].forEach((fieldname) => {
      const input = document.querySelector(`[name="${fieldname}"], #${fieldname}`);
      const container = input?.closest("[data-fieldname], .form-group, .field, .frappe-control");
      if (container) {
        container.style.display = "none";
      }
    });
  }

  function scheduleClassificationFieldVisibility() {
    [0, 150, 500, 1200].forEach((delay) => {
      window.setTimeout(hideCreateOnlyClassificationFields, delay);
    });
  }

  function lockDerivedClassificationFields() {
    const styleId = "haravan-derived-classification-readonly";
    let style = document.getElementById(styleId);
    if (!style) {
      style = document.createElement("style");
      style.id = styleId;
      style.textContent = `
        [data-fieldname="custom_product_suggestion_title"] button,
        [data-fieldname="custom_product_suggestion_title"] [role="button"],
        [data-fieldname="custom_product_line"] button,
        [data-fieldname="custom_product_line"] [role="button"],
        [data-fieldname="custom_product_feature"] button,
        [data-fieldname="custom_product_feature"] [role="button"] {
          display: none !important;
          pointer-events: none !important;
        }
      `;
      document.head.appendChild(style);
    }
  }

  function scheduleDerivedClassificationLock() {
    [0, 200, 700, 1500].forEach((delay) => {
      window.setTimeout(lockDerivedClassificationFields, delay);
    });
  }

  function getPhoneHelpMessage() {
    return "Bắt buộc. Hỗ trợ số quốc tế. Với Việt Nam có thể nhập 0xxxxxxxxx hoặc +84xxxxxxxxx.";
  }

  function normalizePhoneValue(rawValue) {
    const value = String(rawValue || "").trim();
    if (!value) {
      return "";
    }

    let normalized = "";
    let plusSeen = false;

    for (const char of value) {
      if (char >= "0" && char <= "9") {
        normalized += char;
        continue;
      }

      if (char === "+") {
        if (plusSeen || normalized) {
          return null;
        }
        plusSeen = true;
        normalized += char;
        continue;
      }

      if (" ()-./".includes(char)) {
        continue;
      }

      return null;
    }

    return normalized;
  }

  function validatePhoneValue(rawValue) {
    const original = String(rawValue || "").trim();
    if (!original) {
      return {
        valid: false,
        message: "Vui lòng nhập Contact Number."
      };
    }

    const normalized = normalizePhoneValue(original);
    if (!normalized) {
      return {
        valid: false,
        message: "Contact Number chỉ được chứa số và có thể bắt đầu bằng dấu +."
      };
    }

    const digits = normalized.startsWith("+") ? normalized.slice(1) : normalized;
    if (!digits || digits.length < 8 || digits.length > 15) {
      return {
        valid: false,
        message: "Contact Number phải có từ 8 đến 15 chữ số sau khi bỏ khoảng trắng và ký tự ngăn cách."
      };
    }

    if (digits.startsWith("84") && (digits.length < 10 || digits.length > 12)) {
      return {
        valid: false,
        message: "Số điện thoại Việt Nam phải ở dạng 0xxxxxxxxx hoặc +84xxxxxxxxx."
      };
    }

    if (digits.startsWith("0") && (digits.length < 10 || digits.length > 11)) {
      return {
        valid: false,
        message: "Số điện thoại Việt Nam phải ở dạng 0xxxxxxxxx hoặc 0xxxxxxxxxx."
      };
    }

    return {
      valid: true,
      normalized
    };
  }

  function findPhoneInput() {
    const selectors = [
      `input[name="${phoneFieldname}"]`,
      `[data-fieldname="${phoneFieldname}"] input`,
      `[data-fieldname="${phoneFieldname}"] textarea`,
      `#${phoneFieldname}`
    ];

    for (const selector of selectors) {
      const element = document.querySelector(selector);
      if (element) {
        return element;
      }
    }

    return null;
  }

  function ensurePhoneHint(input) {
    if (!input) {
      return null;
    }

    const parent = input.parentElement || input;
    let hint = parent.querySelector("[data-haravan-phone-hint]");
    if (hint) {
      return hint;
    }

    hint = document.createElement("div");
    hint.setAttribute("data-haravan-phone-hint", "1");
    hint.className = "mt-1 text-xs text-slate-500";
    parent.appendChild(hint);
    return hint;
  }

  function findCustomerInput() {
    const selectors = [
      'select[name="customer"]',
      'input[name="customer"]',
      '[data-fieldname="customer"] input',
      '[data-fieldname="customer"] select',
      "#customer"
    ];

    for (const selector of selectors) {
      const element = document.querySelector(selector);
      if (element) {
        return element;
      }
    }

    return null;
  }

  function ensureCustomerHint(input) {
    if (!input) {
      return null;
    }

    const parent = input.parentElement || input;
    let hint = parent.querySelector("[data-haravan-customer-hint]");
    if (hint) {
      return hint;
    }

    hint = document.createElement("div");
    hint.setAttribute("data-haravan-customer-hint", "1");
    hint.className = "mt-1 text-xs text-slate-500";
    parent.appendChild(hint);
    return hint;
  }

  function setPhoneHint(message, tone = "default") {
    const input = findPhoneInput();
    if (!input) {
      return;
    }

    const hint = ensurePhoneHint(input);
    if (!hint) {
      return;
    }

    hint.textContent = message || getPhoneHelpMessage();
    hint.className = "mt-1 text-xs";

    if (tone === "error") {
      hint.classList.add("text-red-600");
      return;
    }

    if (tone === "info") {
      hint.classList.add("text-sky-600");
      return;
    }

    hint.classList.add("text-slate-500");
  }

  function setCustomerHint(message, tone = "default") {
    const input = findCustomerInput();
    if (!input) {
      return;
    }

    const hint = ensureCustomerHint(input);
    if (!hint) {
      return;
    }

    hint.textContent = message || "Nếu tìm thấy lịch sử liên quan, hệ thống sẽ gợi ý Customer phù hợp để bạn chọn lại.";
    hint.className = "mt-1 text-xs";

    if (tone === "info") {
      hint.classList.add("text-sky-600");
      return;
    }

    hint.classList.add("text-slate-500");
  }

  function getPhoneSuggestionMessage() {
    if (!phoneState.suggestedPhones.length) {
      return getPhoneHelpMessage();
    }

    const preview = phoneState.suggestedPhones.slice(0, 3).join(" / ");
    return `Gợi ý từ hồ sơ: ${preview}. Bạn xác nhận hoặc nhập số khác nếu tài khoản đang dùng chung.`;
  }

  function getCustomerSuggestionMessage() {
    if (!customerState.suggestedCustomers.length) {
      return "Nếu tìm thấy lịch sử liên quan, hệ thống sẽ gợi ý Customer phù hợp để bạn chọn lại.";
    }

    const preview = customerState.suggestedCustomers.slice(0, 3).join(", ");
    return `Gợi ý Customer liên quan: ${preview}. Dropdown đã được lọc để bạn tự xác nhận lại.`;
  }

  function dispatchInputEvents(input) {
    input.dispatchEvent(new Event("input", { bubbles: true }));
    input.dispatchEvent(new Event("change", { bubbles: true }));
  }

  function bindPhoneInput(input) {
    if (!input || input.dataset.haravanPhoneBound === "1") {
      return;
    }

    input.dataset.haravanPhoneBound = "1";
    input.required = true;
    input.setAttribute("inputmode", "tel");
    input.setAttribute("autocomplete", "tel");

    const validateSilently = () => syncPhoneField({ showToast: false });
    const validateWithToast = () => syncPhoneField({ showToast: Boolean(input.value) });

    input.addEventListener("input", validateSilently);
    input.addEventListener("change", validateWithToast);
    input.addEventListener("blur", validateWithToast);
  }

  function applyNormalizedPhone(input, normalized) {
    if (!input || !normalized) {
      return;
    }

    if (String(input.value || "").trim() === normalized) {
      return;
    }

    input.value = normalized;
    dispatchInputEvents(input);
  }

  function syncPhoneField({ showToast = false } = {}) {
    const input = findPhoneInput();
    if (!input) {
      return false;
    }

    bindPhoneInput(input);

    const rawValue = String(input.value || doc[phoneFieldname] || "").trim();
    const result = validatePhoneValue(rawValue);

    if (!rawValue) {
      input.setCustomValidity("Vui lòng nhập Contact Number.");
      if (phoneState.suggestedPhones.length) {
        setPhoneHint(getPhoneSuggestionMessage(), "info");
      } else {
        setPhoneHint(getPhoneHelpMessage());
      }

      if (showToast) {
        createToast?.({
          title: "Thiếu Contact Number",
          message: "Vui lòng nhập Contact Number trước khi tạo ticket.",
          variant: "error"
        });
      }
      return false;
    }

    if (!result.valid) {
      input.setCustomValidity(result.message);
      setPhoneHint(result.message, "error");
      if (showToast) {
        createToast?.({
          title: "Contact Number chưa đúng",
          message: result.message,
          variant: "error"
        });
      }
      return false;
    }

    input.setCustomValidity("");
    if (result.normalized !== rawValue) {
      applyNormalizedPhone(input, result.normalized);
    }

    if (phoneState.suggestedPhones.length) {
      setPhoneHint(getPhoneSuggestionMessage(), "info");
    } else {
      setPhoneHint(getPhoneHelpMessage());
    }

    return true;
  }

  function bindSubmitGuard() {
    if (phoneState.submitBound) {
      return;
    }

    phoneState.submitBound = true;
    document.addEventListener("submit", (event) => {
      const isValid = syncPhoneField({ showToast: true });
      if (isValid) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      const input = findPhoneInput();
      if (input) {
        input.focus();
      }
    }, true);
  }

  function schedulePhoneDomSync() {
    [0, 200, 800].forEach((delay) => {
      window.setTimeout(() => {
        const input = findPhoneInput();
        if (!input) {
          return;
        }

        bindPhoneInput(input);
        syncPhoneField({ showToast: false });
      }, delay);
    });
  }

  async function loadContactRecord(contactValue) {
    const trimmedValue = String(contactValue || "").trim();
    if (!trimmedValue) {
      return null;
    }

    const directMatch = await call("frappe.client.get", {
      doctype: "Contact",
      name: trimmedValue
    }).catch((error) => {
      console.error("[HD Ticket Intake] Unable to load contact by name", trimmedValue, error);
      return null;
    });

    if (directMatch) {
      return directMatch;
    }

    if (!trimmedValue.includes("@")) {
      return null;
    }

    const matchedRows = await call("frappe.client.get_list", {
      doctype: "Contact",
      fields: ["name"],
      filters: { email_id: trimmedValue },
      limit_page_length: 1
    }).catch((error) => {
      console.error("[HD Ticket Intake] Unable to match contact by email", trimmedValue, error);
      return [];
    });

    const matchedName = matchedRows?.[0]?.name;
    if (!matchedName) {
      return null;
    }

    return call("frappe.client.get", {
      doctype: "Contact",
      name: matchedName
    }).catch((error) => {
      console.error("[HD Ticket Intake] Unable to load matched contact", matchedName, error);
      return null;
    });
  }

  function collectCandidateEmails(contact, contactValue, email) {
    const suggestions = [email];
    const trimmedContactValue = String(contactValue || "").trim();
    if (trimmedContactValue.includes("@")) {
      suggestions.push(trimmedContactValue);
    }

    if (contact) {
      suggestions.push(contact.email_id);
      (contact.email_ids || []).forEach((row) => suggestions.push(row && row.email_id));
    }

    return unique(suggestions);
  }

  async function loadPossiblePhones(contactValue, email) {
    const suggestions = [];
    const contact = await loadContactRecord(contactValue);

    if (contact) {
      suggestions.push(contact.mobile_no, contact.phone);
      (contact.phone_nos || []).forEach((row) => suggestions.push(row && row.phone));
    }

    const historyFilters = [];
    if (contact?.name) {
      historyFilters.push({ contact: contact.name });
    }
    collectCandidateEmails(contact, contactValue, email).forEach((candidateEmail) => {
      historyFilters.push({ raised_by: candidateEmail });
    });

    const responses = await Promise.all(
      historyFilters.map((filters) =>
        call("frappe.client.get_list", {
          doctype: "HD Ticket",
          fields: ["custom_contact_phone"],
          filters,
          limit_page_length: 5,
          order_by: "creation desc"
        }).catch((error) => {
          console.error("[HD Ticket Intake] Unable to load phone history", filters, error);
          return [];
        })
      )
    );

    responses.flat().forEach((row) => suggestions.push(row && row.custom_contact_phone));

    return unique(
      suggestions
        .map((value) => {
          const result = validatePhoneValue(value);
          return result.valid ? result.normalized : "";
        })
        .filter(Boolean)
    );
  }

  async function loadPossibleCustomers(contactValue) {
    if (!contactValue) {
      return [];
    }

    const contact = await loadContactRecord(contactValue);
    const customerSuggestions = [];

    if (contact) {
      customerSuggestions.push(
        ...unique(
          (contact.links || [])
            .filter((row) => row.link_doctype === "HD Customer")
            .map((row) => row.link_name)
        )
      );
    }

    const historyFilters = [];
    if (contact?.name) {
      historyFilters.push({ contact: contact.name });
    }
    collectCandidateEmails(contact, contactValue).forEach((candidateEmail) => {
      historyFilters.push({ raised_by: candidateEmail });
    });

    const responses = await Promise.all(
      historyFilters.map((filters) =>
        call("frappe.client.get_list", {
          doctype: "HD Ticket",
          fields: ["customer"],
          filters,
          limit_page_length: 20,
          order_by: "creation desc"
        }).catch((error) => {
          console.error("[HD Ticket Intake] Unable to load customer history", filters, error);
          return [];
        })
      )
    );

    customerSuggestions.push(...responses.flat().map((row) => row && row.customer));

    return unique(customerSuggestions);
  }

  async function syncCustomerSuggestions(contactName, showFeedback = false) {
    const requestId = customerState.requestId + 1;
    customerState.requestId = requestId;
    const customerNames = await loadPossibleCustomers(contactName);
    if (customerState.requestId !== requestId) {
      return;
    }

    customerState.suggestedCustomers = customerNames;
    applyFilters("customer", customerNames.length ? customerNames : null);
    setCustomerHint(getCustomerSuggestionMessage(), customerNames.length ? "info" : "default");

    if (!showFeedback || !contactName) {
      return;
    }

    if (customerNames.length === 1) {
      createToast?.({
        title: "Đã gợi ý Customer",
        message: `Đã tìm thấy Customer phù hợp: ${customerNames[0]}. Dropdown đã được lọc để bạn tự xác nhận lại.`,
        variant: "info"
      });
      return;
    }

    if (customerNames.length > 1) {
      createToast?.({
        title: "Chọn Customer",
        message: `Contact này liên quan đến ${customerNames.length} customer. Dropdown Customer đã được lọc theo danh sách phù hợp.`,
        variant: "info"
      });
      return;
    }

    createToast?.({
      title: "Chưa có Customer gợi ý",
      message: "Không tìm thấy Customer rõ ràng từ lịch sử contact này. Bạn có thể chọn thủ công nếu cần.",
      variant: "info"
    });
  }

  async function syncPhoneSuggestion({ contactValue = doc.contact, emailValue = doc.raised_by, showFeedback = false } = {}) {
    const requestId = phoneState.requestId + 1;
    phoneState.requestId = requestId;
    const suggestions = await loadPossiblePhones(contactValue, emailValue);
    if (phoneState.requestId !== requestId) {
      return;
    }

    phoneState.suggestedPhones = suggestions;

    schedulePhoneDomSync();

    if (!phoneState.suggestedPhones.length) {
      return;
    }

    const input = findPhoneInput();
    if (input) {
      bindPhoneInput(input);
      syncPhoneField({ showToast: false });
    }

    if (showFeedback) {
      createToast?.({
        title: "Đã gợi ý Contact Number",
        message: `Hệ thống tìm thấy ${phoneState.suggestedPhones.join(" / ")} từ hồ sơ hiện có. Bạn xác nhận hoặc nhập số khác nếu cần.`,
        variant: "info"
      });
    }
  }

  function syncAll() {
    applyFilters("custom_category", productOptions(doc.ticket_type));
    applyFilters("custom_sub_category", functionOptions(doc.custom_category));
  }



  // Haravan Agent Intake Template Patch
  // Goal: On /helpdesk/tickets/new, agents do not see derived fields.
  // Server Scripts still fill Customer, Org ID, MyHaravan Domain, Product Line, Product Feature.
  function applyAgentIntakeTemplatePatch() {
    if (!isNewTicketForm()) {
      return;
    }

    const hiddenLabels = ["Customer", "Org ID", "MyHaravan Domain", "Product Line", "Product Feature"];
    const hiddenFieldnames = [
      "customer",
      "custom_orgid",
      "custom_my_haravan_domain",
      "custom_myharavan_domain",
      "custom_product_line",
      "custom_product_feature"
    ];
    const requiredLabels = ["Link Web / MyHaravan", "Product Suggestion"];

    function cleanText(value) {
      return String(value || "").replace(/\s+/g, " ").replace(/ \*/g, "").trim();
    }

    function hideElement(element) {
      if (!element) return;
      element.style.setProperty("display", "none", "important");
      element.setAttribute("data-haravan-agent-hidden", "1");
    }

    function hideByFieldname(fieldname) {
      document.querySelectorAll(`[name="${fieldname}"], #${fieldname}, [data-fieldname="${fieldname}"]`).forEach((node) => {
        hideElement(node.closest("[data-fieldname], .form-group, .field, .frappe-control") || node.parentElement || node);
      });
    }

    function findContainerByLabel(labelText) {
      const nodes = document.querySelectorAll("label, div, span, p");
      for (const node of nodes) {
        if (cleanText(node.textContent) !== labelText) continue;
        let current = node;
        for (let depth = 0; current && depth < 8; depth += 1) {
          if (current !== document.body && current.querySelector && current.querySelector("input, textarea, select, button, [role='combobox']")) {
            return current;
          }
          current = current.parentElement;
        }
      }
      return null;
    }

    hiddenFieldnames.forEach(hideByFieldname);
    hiddenLabels.forEach((label) => hideElement(findContainerByLabel(label)));

    requiredLabels.forEach((labelText) => {
      const container = findContainerByLabel(labelText);
      const label = container?.querySelector("label, div, span, p");
      if (label && !label.querySelector("[data-haravan-required-star]")) {
        const star = document.createElement("span");
        star.setAttribute("data-haravan-required-star", "1");
        star.style.color = "#dc2626";
        star.textContent = " *";
        label.appendChild(star);
      }
    });
  }

  function scheduleAgentIntakeTemplatePatch() {
    [0, 100, 300, 700, 1200, 2500, 5000].forEach((delay) => {
      window.setTimeout(applyAgentIntakeTemplatePatch, delay);
    });

    if (!window.__haravanAgentIntakeTemplatePatchObserver) {
      window.__haravanAgentIntakeTemplatePatchObserver = true;
      const observer = new MutationObserver(() => applyAgentIntakeTemplatePatch());
      observer.observe(document.body, { childList: true, subtree: true });
    }
  }

  syncAll();
  scheduleAgentIntakeTemplatePatch();
  scheduleClassificationFieldVisibility();
  scheduleDerivedClassificationLock();
  bindSubmitGuard();
  schedulePhoneDomSync();
  syncPhoneSuggestion({ showFeedback: false });
  syncCustomerSuggestions(doc.contact, false);

  return {
    onChange: {
      ticket_type: () => syncAll(),
      custom_category: () => {
        applyFilters("custom_sub_category", functionOptions(doc.custom_category));
      },
      contact: async (newVal) => {
        await syncCustomerSuggestions(newVal, true);
        await syncPhoneSuggestion({ contactValue: newVal, emailValue: doc.raised_by, showFeedback: true });
      },
      raised_by: async (newVal) => {
        await syncPhoneSuggestion({ contactValue: doc.contact, emailValue: newVal || doc.raised_by, showFeedback: false });
      },
      custom_contact_phone: () => {
        schedulePhoneDomSync();
        window.setTimeout(() => syncPhoneField({ showToast: true }), 0);
      }
    }
  };
}
